    match self.poll_inner() {
        PollFuture::Notified  => { self.core().scheduler.yield_now(Notified(self.get_new_task())); self.drop_reference(); }
        PollFuture::Complete  => { self.complete(); }
        PollFuture::Dealloc   => { self.dealloc(); }
        PollFuture::Done      => (),
    }
}
